targets.expr:
topk(100, sum(
    rate(container_cpu_usage_seconds_total{namespace="$namespace", pod=~"($deployment|$daemonset|$statefulset).+", container!=""}[1m])
) by (pod, container) * 1000)

min(sum(
    kube_pod_container_resource_limits{namespace="$namespace", pod=~'($deployment|$daemonset|$statefulset).+', resource='cpu', node=~".+"} 
) by (pod)) * 1000

min(sum(
    kube_pod_container_resource_limits{namespace="$namespace", pod=~'($deployment|$daemonset|$statefulset).+', resource='cpu', node=~".+"} 
) by (pod)) * 1.25 * 1000

